    let data = await fetchData()  // error: async in non-async function
}

// AFTER (correct) - Option 1: make function async:
func loadData() async {
    let data = await fetchData()
}

// AFTER (correct) - Option 2: use Task:
func loadData() {
    Task {
        let data = await fetchData()
    }
}

