// BEFORE (wrong):
struct Timer {
    var elapsed = 0
    mutating func start() {
        DispatchQueue.main.async {
            self.elapsed += 1  // error: escaping closure captures mutating self
        }
    }
}

// AFTER (correct) - use a class:
class Timer {
    var elapsed = 0
    func start() {
        DispatchQueue.main.async { [weak self] in
            self?.elapsed += 1
        }
    }
}

