// BEFORE (potential cycle):
class ViewModel {
    var onUpdate: (() -> Void)?
    func setup() {
        onUpdate = { self.refresh() }  // strong reference cycle
    }
}

// AFTER (correct):
class ViewModel {
    var onUpdate: (() -> Void)?
    func setup() {
        onUpdate = { [weak self] in self?.refresh() }
    }
}

