// This struct is internal (default) - visible in same module only:
struct Config { var timeout: Int }

// This struct is public - visible to other modules:
public struct APIConfig { public var timeout: Int }

extension Array: Equatable where Element: Equatable { }
// [Int] is Equatable (Int: Equatable)
// [UIView] is NOT Equatable (UIView is not Equatable)

@MainActor
class ViewModel {
    var title = ""  // main-actor isolated
}

// Must be called on main actor or with await:
func update(vm: ViewModel) async {
    await vm.title = "New"  // crosses isolation boundary
}

// This may be too complex:
let result = items.lazy.filter { $0.isValid }.map { $0.value }.reduce(0, +)

// Fix: add type annotations:
let filtered: [Item] = items.filter { $0.isValid }
let values: [Int] = filtered.map { $0.value }
let result: Int = values.reduce(0, +)

class Model: ObservableObject {
    @Published var name: String = ""  // name is String, $name is Published<String>.Publisher
}

struct MyView: View {
    @State var count = 0  // count is Int, $count is Binding<Int>
}

// Each line in a @ViewBuilder produces a View:
var body: some View {
    Text("Hello")       // View
    if condition {
        Image("photo")  // View
    }                    // Both branches must return Views
    42                   // Error: Int is not a View
}

